   321→    });
   322→
   323→    it('should validate confidence thresholds on initialization', () => {
   324→      const invalidThresholds: CategoryConfiguration = {
   325→        ...minimalConfig,
   326→        processingConfig: {
   327→          ...minimalProcessingConfig,
   328→          confidenceThresholds: {
   329→            highConfidence: -0.1, // Invalid negative value
   330→            mediumConfidence: 0.5,
