   342→  describe('Stage Execution Order', () => {
   343→    it('should execute all 10 stages in correct order when AI is skipped', async () => {
   344→      const pipeline = new ClassificationPipeline(minimalConfig);
   345→      await pipeline.classify(mockEmail);
   346→
