   353→      expect(executeDisambiguation).toHaveBeenCalled();
   354→      expect(executeMultiLabelSelection).toHaveBeenCalled();
   355→      expect(aiRoutingStage).toHaveBeenCalled();
   356→
   357→      // AI stages should not be called (needsAiClassification = false by mock)
   358→      expect(aiFeatureExtractionStage).not.toHaveBeenCalled();
   359→      expect(aiClassificationStage).not.toHaveBeenCalled();
   360→      expect(aiLabelFilteringStage).not.toHaveBeenCalled();
   361→
