   390→      (executeAttributeDetection as jest.Mock).mockImplementation(() => callOrder.push('attribute-detection'));
   391→      (executeAttributeInfluence as jest.Mock).mockImplementation(() => callOrder.push('attribute-influence'));
   392→      (executeDisambiguation as jest.Mock).mockImplementation(() => callOrder.push('disambiguation'));
   393→      (executeMultiLabelSelection as jest.Mock).mockImplementation(() => callOrder.push('multi-label'));
