   566→  describe('Conditional AI Flow', () => {
   567→    it('should skip AI stages when high confidence', async () => {
   568→      const pipeline = new ClassificationPipeline(minimalConfig);
   569→      await pipeline.classify(mockEmail);
   570→
   571→      expect(aiFeatureExtractionStage).not.toHaveBeenCalled();
   572→      expect(aiClassificationStage).not.toHaveBeenCalled();
