      allowFinancialActionableCopresence: false,
    },
    domainSignalOverrides: {},
    domainSignalResolution: {
      mode: 'runtimeResolved',
      source: 'config/domain-sources.json',
      notes: 'Test configuration',
    },
    topLevelCategories: {},
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    },
    aiPrompts: {
      featureExtraction: {
        systemPrompt: [],
        userPrompt: [],
      },
      finalClassification: {
        systemPrompt: [],
        userPrompt: [],
      },
    },
    featureExtractionSchema: {
      type: 'object',
      properties: {},
      required: [],
      additionalProperties: false,
    },
  };

  const minimalConfig: CategoryConfiguration = {
    version: '1.0.0',
    lastModified: new Date(),
    hash: 'test-config-hash',
    processingConfig: minimalProcessingConfig,
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  beforeEach(() => {
    // Clear only mock calls, not implementations
    jest.clearAllMocks();

    // Re-apply default mock implementations
    (executeHardAssertions as jest.Mock).mockImplementation((email, session, result) => {
      result.candidateScores.financial = { score: 15, hardAssertion: true };
    });
    (executeStrongIndicators as jest.Mock).mockImplementation((email, session, result) => {
      result.candidateScores.personal = { score: 10, seedScore: 10 };
    });
    (executeRuleScoring as jest.Mock).mockImplementation((email, session, result) => {
      result.candidateScores.financial = {
        ...result.candidateScores.financial,
        score: 15.5,
