/**
 * Unit Tests for Audit Trail Generation Stage (T036)
 *
 * Tests validate:
 * - Complete explainability trace generation from all 10 pipeline stages
 * - Stage result aggregation and consolidation
 * - JSON serialization and data integrity
 * - Performance metadata tracking
 * - Configuration reference collection
 * - Database persistence format compatibility
 */

import { generateAuditTrail, PipelineResults, AuditTrailConfig } from '../../src/stages/audit-trail';
import { EmailMessage, ClassificationSession } from '../../src/types';

describe('Audit Trail Generation Stage', () => {
  // Mock email and session data
  const mockEmail: EmailMessage = {
    id: 'email-123',
    threadId: 'thread-123',
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'Subject', value: 'Test Email' },
        { name: 'Date', value: 'Tue, 30 Sep 2025 10:00:00 +0000' },
      ],
    },
    subject: 'Test Email',
    from: { email: 'sender@example.com', name: 'Sender', raw: 'Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date('2025-09-30T10:00:00Z'),
    isProcessed: false,
    processingPriority: 0,
  };

  const mockSession: ClassificationSession = {
    id: 'session-456',
    startedAt: new Date('2025-09-30T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  const mockConfig: AuditTrailConfig = {
    includePerformanceMetrics: true,
    includeConfigurationRefs: true,
    serializationFormat: 'json',
  };

  describe('Complete Explainability Trace Generation', () => {
    it('should aggregate results from all 10 pipeline stages', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: {
          appliedAssertions: [
            {
              category: 'financial',
              assertionType: 'fromDomain',
              matchedValue: 'chase.com',
              confidence: 'HIGH_CONFIDENCE',
              triggered: true,
              reason: 'Domain matched hard assertion for financial category',
            },
          ],
          processingDurationMs: 5,
        },
        strongIndicators: {
          appliedIndicators: [
            {
              category: 'financial',
              indicatorType: 'subjectContains',
              matchedValue: 'invoice',
              seedScore: 10,
              diminishingReturnsApplied: false,
              existingSeedScore: 0,
              finalSeedScore: 10,
              reason: 'Subject contains financial keyword',
            },
          ],
          processingDurationMs: 8,
        },
        ruleScoring: {
          categoryScores: { financial: 15.2 },
          subtypeScores: { financial: { invoice: 12, billDue: 8 } },
          processingDurationMs: 45,
        },
        attributeDetection: {
          detectedAttributes: [
            {
              attribute: 'hasAmount',
              detected: true,
              detectionMethod: 'direct',
              sourceField: 'body',
              confidence: 0.95,
              parallelProcessed: true,
              dependencies: [],
              reason: 'Amount pattern detected in body',
            },
          ],
          processingDurationMs: 20,
        },
        attributeInfluence: {
          appliedInfluences: [
            {
              targetCategory: 'financial',
              attributeUsed: 'hasAmount',
              roleType: 'PRIMARY_BOOST',
              bonusAmount: 2,
              scoreBefore: 15.2,
              scoreAfter: 17.2,
              capApplied: false,
              reason: 'Amount attribute boosted financial category',
            },
          ],
          processingDurationMs: 12,
        },
        disambiguation: {
          adjustments: [],
          processingDurationMs: 5,
        },
        multiLabelSelection: {
          selectedLabels: [
            {
              category: 'financial',
              subtype: 'invoice',
              confidence: 0.92,
              score: 17.2,
              isPrimary: true,
              labelOrder: 1,
              selectionRationale: 'Highest scoring category with hard assertion',
            },
          ],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'financial',
            confidenceRange: [0.92, 0.92],
            selectionMethod: 'singleLabel',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skipAi',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: ['highConfidenceScore', 'hardAssertionPresent'],
          reason: 'High confidence classification, AI not needed',
          processingDurationMs: 3,
        },
        aiLabelFiltering: {
          assignedLabels: {
            primary: 'financial',
            secondary: [],
          },
          processingDurationMs: 8,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: 'financial',
              secondaryCategories: [],
              confidence: 0.92,
              reasoning: 'High confidence direct classification',
              categoryScores: { financial: 17.2 },
            },
            labelAssignmentRationale: 'Primary category assigned based on highest score',
            filteredLabels: [],
          },
        },
        actionDetermination: {
          determinedActions: ['markAsRead'],
          actionReasoning: 'Financial emails are marked as read automatically',
          processingDurationMs: 10,
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      // Validate trace includes all 10 stages
      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.attributeDetection).toHaveLength(1);
      expect(result.explainabilityTrace.attributeInfluence).toHaveLength(1);
      expect(result.explainabilityTrace.disambiguation).toEqual([]);
      expect(result.explainabilityTrace.multiLabelSelection).toHaveLength(1);
      expect(result.explainabilityTrace.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();

      // Validate final decision reason includes action information
      expect(result.explainabilityTrace.finalDecisionReason).toContain('financial');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('markAsRead');
    });

    it('should include performance metadata from all 10 stages', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: { appliedAssertions: [], processingDurationMs: 5 },
        strongIndicators: { appliedIndicators: [], processingDurationMs: 8 },
        ruleScoring: { categoryScores: {}, subtypeScores: {}, processingDurationMs: 45 },
        attributeDetection: { detectedAttributes: [], processingDurationMs: 20 },
        attributeInfluence: { appliedInfluences: [], processingDurationMs: 12 },
        disambiguation: { adjustments: [], processingDurationMs: 5 },
        multiLabelSelection: {
          selectedLabels: [],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 0,
            primaryCategory: null,
            confidenceRange: [0, 0],
            selectionMethod: 'noneSelected',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skipAi',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: [],
          reason: 'No clear decision',
          processingDurationMs: 3,
        },
        aiLabelFiltering: {
          assignedLabels: { primary: 'unknown', secondary: [] },
          processingDurationMs: 10,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: 'unknown',
              secondaryCategories: [],
              confidence: 0,
              reasoning: '',
              categoryScores: {},
            },
            labelAssignmentRationale: '',
            filteredLabels: [],
          },
        },
        actionDetermination: {
          determinedActions: [],
          actionReasoning: 'No actions determined',
          processingDurationMs: 5,
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      expect(result.explainabilityTrace.stageTimings).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.hardAssertions).toBe(5);
      expect(result.explainabilityTrace.stageTimings.strongIndicators).toBe(8);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBe(45);
      expect(result.explainabilityTrace.stageTimings.attributeDetection).toBe(20);
      expect(result.explainabilityTrace.stageTimings.attributeInfluence).toBe(12);
      expect(result.explainabilityTrace.stageTimings.disambiguation).toBe(5);
      expect(result.explainabilityTrace.stageTimings.multiLabelSelection).toBe(15);
      expect(result.explainabilityTrace.stageTimings.aiRouting).toBe(3);
      expect(result.explainabilityTrace.stageTimings.aiLabelFiltering).toBe(10);

      // Note: actionDetermination timing is not included in stageTimings (it's tracked separately)
      // Total processing time for stages 1-8d
      const totalTime = Object.values(result.explainabilityTrace.stageTimings).reduce((sum, time) => sum + time, 0);
      expect(totalTime).toBe(123); // Sum of all tracked stage times
    });

    it('should track parallel execution metadata', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: { appliedAssertions: [], processingDurationMs: 5 },
        strongIndicators: { appliedIndicators: [], processingDurationMs: 8 },
        ruleScoring: { categoryScores: {}, subtypeScores: {}, processingDurationMs: 45 },
        attributeDetection: {
          detectedAttributes: [
            {
              attribute: 'hasAmount',
              detected: true,
              detectionMethod: 'direct',
              confidence: 0.95,
              parallelProcessed: true,
              dependencies: [],
              reason: 'Detected in parallel batch',
            },
            {
              attribute: 'hasDueDate',
              detected: true,
              detectionMethod: 'direct',
              confidence: 0.9,
              parallelProcessed: true,
              dependencies: [],
              reason: 'Detected in parallel batch',
            },
          ],
          processingDurationMs: 20,
        },
        attributeInfluence: { appliedInfluences: [], processingDurationMs: 12 },
        disambiguation: { adjustments: [], processingDurationMs: 5 },
        multiLabelSelection: {
          selectedLabels: [],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 0,
            primaryCategory: null,
            confidenceRange: [0, 0],
            selectionMethod: 'noneSelected',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skipAi',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: [],
          reason: '',
          processingDurationMs: 3,
        },
        aiLabelFiltering: {
          assignedLabels: { primary: 'unknown', secondary: [] },
          processingDurationMs: 10,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: 'unknown',
              secondaryCategories: [],
              confidence: 0,
              reasoning: '',
              categoryScores: {},
            },
            labelAssignmentRationale: '',
            filteredLabels: [],
          },
        },
        actionDetermination: {
          determinedActions: [],
          actionReasoning: '',
          processingDurationMs: 5,
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      expect(result.explainabilityTrace.parallelExecutionMap).toBeDefined();
      expect(result.explainabilityTrace.parallelExecutionMap.attributeDetection).toContain('hasAmount');
      expect(result.explainabilityTrace.parallelExecutionMap.attributeDetection).toContain('hasDueDate');
    });
  });

  describe('Action Determination Stage Validation', () => {
    it('should capture action determination results in audit trail', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: { appliedAssertions: [], processingDurationMs: 5 },
        strongIndicators: { appliedIndicators: [], processingDurationMs: 8 },
        ruleScoring: { categoryScores: { financial: 18.5 }, subtypeScores: {}, processingDurationMs: 45 },
        attributeDetection: { detectedAttributes: [], processingDurationMs: 20 },
        attributeInfluence: { appliedInfluences: [], processingDurationMs: 12 },
        disambiguation: { adjustments: [], processingDurationMs: 5 },
        multiLabelSelection: {
          selectedLabels: [
            {
              category: 'financial',
              subtype: 'invoice',
              confidence: 0.95,
              score: 18.5,
              isPrimary: true,
              labelOrder: 1,
              selectionRationale: 'High confidence financial email',
            },
          ],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'financial',
            confidenceRange: [0.95, 0.95],
            selectionMethod: 'singleLabel',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skipAi',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: ['highConfidenceScore'],
          reason: 'High confidence, AI not needed',
          processingDurationMs: 3,
        },
        aiLabelFiltering: {
          assignedLabels: { primary: 'financial', secondary: [] },
          processingDurationMs: 8,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: 'financial',
              secondaryCategories: [],
              confidence: 0.95,
              reasoning: 'Direct classification',
              categoryScores: { financial: 18.5 },
            },
            labelAssignmentRationale: 'Primary label assigned',
            filteredLabels: [],
          },
        },
        actionDetermination: {
          determinedActions: ['archive', 'markAsRead'],
          actionReasoning: 'High confidence financial email - archive and mark as read',
          processingDurationMs: 12,
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      // Verify actions are included in final decision reason
      expect(result.explainabilityTrace.finalDecisionReason).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('markAsRead');
    });

    it('should run action determination even when AI is skipped', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: { appliedAssertions: [], processingDurationMs: 5 },
        strongIndicators: { appliedIndicators: [], processingDurationMs: 8 },
        ruleScoring: { categoryScores: { personal: 16.0 }, subtypeScores: {}, processingDurationMs: 45 },
        attributeDetection: { detectedAttributes: [], processingDurationMs: 20 },
        attributeInfluence: { appliedInfluences: [], processingDurationMs: 12 },
        disambiguation: { adjustments: [], processingDurationMs: 5 },
        multiLabelSelection: {
          selectedLabels: [
            {
              category: 'personal',
              subtype: null,
              confidence: 0.88,
              score: 16.0,
              isPrimary: true,
              labelOrder: 1,
              selectionRationale: 'Personal category selected',
            },
          ],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'personal',
            confidenceRange: [0.88, 0.88],
            selectionMethod: 'singleLabel',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skipAi',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: ['highConfidenceScore'],
          reason: 'Confidence above threshold',
          processingDurationMs: 3,
        },
        aiLabelFiltering: {
          assignedLabels: { primary: 'personal', secondary: [] },
          processingDurationMs: 8,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: 'personal',
              secondaryCategories: [],
              confidence: 0.88,
              reasoning: '',
              categoryScores: { personal: 16.0 },
            },
            labelAssignmentRationale: 'Direct assignment without AI',
            filteredLabels: [],
          },
        },
        actionDetermination: {
          determinedActions: [],
          actionReasoning: 'No specific actions for personal emails',
          processingDurationMs: 8,
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      // Verify audit trail includes classification without AI
      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toContain('personal');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Final assignment');

      // When no actions determined, "Actions:" should not appear in final decision reason
      expect(result.explainabilityTrace.finalDecisionReason).not.toContain('Actions:');
